    {
      "cell_type": "markdown",
      "source": [
        "**SECTION 4: FEATURE ENGINEERING**"
      ],
      "metadata": {
        "id": "9HkvcORIy2um"
      }
    },
    {
      "cell_type": "code",
      "source": [
        "df['total_delay']      = df['dep_delay'] + df['arr_delay']\n",
        "df['is_on_time']       = df['arr_delay'] <= 15\n",
        "df['is_severely_late'] = df['dep_delay'] > 60"
      ],
      "metadata": {
        "id": "7YAqF2iby5mu"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "code",
      "source": [
        "delay_mag_bins   = [-float('inf'), 0, 15, 60, 120, float('inf')]\n",
        "delay_mag_labels = ['Early / On Time', 'Minor (1–15 min)',\n",
        "                    'Moderate (16–60 min)', 'Severe (61–120 min)', 'Extreme (>120 min)']\n",
        "df['delay_magnitude'] = pd.cut(df['dep_delay'], bins=delay_mag_bins, labels=delay_mag_labels)"
      ],
      "metadata": {
        "id": "JWniwq3By_e2"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "markdown",
      "source": [
        "Time features"
      ],
      "metadata": {
        "id": "jMPxBc-4zFzG"
      }
    },
    {
      "cell_type": "code",
      "source": [
        "df['season'] = pd.cut(df['month'],\n",
        "    bins=[0, 2, 5, 8, 11, 12],\n",
        "    labels=['Winter', 'Spring', 'Summer', 'Autumn', 'Winter'],\n",
        "    ordered=False\n",
        ")\n",
        "\n",
        "df['season'] = df['season'].astype(str)"
      ],
      "metadata": {
        "id": "LqXMT6L1zOsx"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "code",
      "source": [
        "df['scheduled_departure_hour'] = df['crs_dep_time'] // 100\n",
        "df['is_weekend'] = df['day_of_week'].isin([6, 7])"
      ],
      "metadata": {
        "id": "MWwTa1RS_PVm"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "code",
      "source": [
        "df['day_type'] = df['is_weekend'].map({True: 'Weekend', False: 'Weekday'})"
      ],
      "metadata": {
        "id": "_grvbzgh_S52"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "markdown",
      "source": [
        "Aircraft performance"
      ],
      "metadata": {
        "id": "Cq-6nqXCzSZO"
      }
    },
    {
      "cell_type": "code",
      "source": [
        "df['schedule_padding'] = df['crs_elapsed_time'] - df['actual_elapsed_time']\n",
        "df['ground_speed'] = df['distance'] / df['air_time']"
      ],
      "metadata": {
        "id": "GWTyLcN8zTAX"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "code",
      "source": [
        "padding_bins   = [-float('inf'), -10, 0, 10, 20, float('inf')]\n",
        "padding_labels = ['Severely Under-padded (<-10 min)', 'Slightly Under-padded (-10–0 min)',\n",
        "                  'Tight Padding (0–10 min)', 'Moderate Padding (10–20 min)', 'Heavy Padding (>20 min)']\n",
        "df['padding_category'] = pd.cut(df['schedule_padding'], bins=padding_bins, labels=padding_labels)"
      ],
      "metadata": {
        "id": "bxw5ynB7zWSq"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "markdown",
      "source": [
        "Flight classification"
      ],
      "metadata": {
        "id": "O7MH8KY2zbze"
      }
    },
    {
      "cell_type": "code",
      "source": [
        "df['flight_type'] = np.where(df['distance'] > 1800, 'Long-haul', 'Short-haul')"
      ],
      "metadata": {
        "id": "_bGrhaMpzdUZ"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "markdown",
      "source": [
        "Distance bands (used in route analysis)"
      ],
      "metadata": {
        "id": "nLH40iknzmVY"
      }
    },
    {
      "cell_type": "code",
      "source": [
        "dist_bins = [0, 500, 1000, 1500, 2000, 3000, float('inf')]\n",
        "dist_labels = ['<500mi', '500–1000mi', '1000–1500mi', '1500–2000mi', '2000–3000mi', '>3000mi']"
      ],
      "metadata": {
        "id": "znMZGSbS_khs"
      },
      "execution_count": null,
      "outputs": []
    },
    {
      "cell_type": "code",
      "source": [
        "df['distance_band'] = pd.cut(df['distance'], bins=dist_bins, labels=dist_labels)"
      ],
      "metadata": {
        "id": "tD7UhmAb_nLM"
      },
      "execution_count": null,
      "outputs": []
    },
